import{_ as a,a as t,i as r,o as i}from"./chunks/framework.CXVo2Jqr.js";const u=JSON.parse('{"title":"Quick Start","description":"","frontmatter":{"outline":"deep","title":"Quick Start"},"headers":[],"relativePath":"en/introduction.md","filePath":"en/introduction.md","lastUpdated":1773568036000}'),n={name:"en/introduction.md"};function o(s,e,l,d,c,h){return i(),t("div",null,e[0]||(e[0]=[r(`<h1 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h1><p>Welcome to Tiger Origin! This is an easy-to-learn and powerful shape-based input method.</p><h2 id="🎯-why-choose-tiger-origin" tabindex="-1">🎯 Why Choose Tiger Origin? <a class="header-anchor" href="#🎯-why-choose-tiger-origin" aria-label="Permalink to &quot;🎯 Why Choose Tiger Origin?&quot;">​</a></h2><h3 id="easy-to-learn" tabindex="-1">Easy to Learn <a class="header-anchor" href="#easy-to-learn" aria-label="Permalink to &quot;Easy to Learn&quot;">​</a></h3><ul><li><strong>Only 20 Core Radicals</strong> - Compared to Wubi&#39;s 130+ radicals, greatly reducing the learning curve</li><li><strong>Get Started in 30 Minutes</strong> - Beginners can quickly master radical encoding</li><li><strong>Intuitive Design</strong> - Radical design is intuitive and easy to remember</li></ul><h3 id="efficient-input" tabindex="-1">Efficient Input <a class="header-anchor" href="#efficient-input" aria-label="Permalink to &quot;Efficient Input&quot;">​</a></h3><ul><li><strong>Four-Code Fixed Length</strong> - Maximum 4 letters input</li><li><strong>Low Duplication Rate</strong> - Smooth typing without frequent word selection</li><li><strong>Scientific Character Decomposition</strong> - Based on Chinese character origin and structure, following natural patterns</li></ul><h3 id="wide-application" tabindex="-1">Wide Application <a class="header-anchor" href="#wide-application" aria-label="Permalink to &quot;Wide Application&quot;">​</a></h3><ul><li>Daily office work, professional writing, programming development</li><li>Full platform support for Windows and Android</li></ul><h2 id="🚀-quick-start" tabindex="-1">🚀 Quick Start <a class="header-anchor" href="#🚀-quick-start" aria-label="Permalink to &quot;🚀 Quick Start&quot;">​</a></h2><h3 id="step-1-understand-the-radicals" tabindex="-1">Step 1: Understand the Radicals <a class="header-anchor" href="#step-1-understand-the-radicals" aria-label="Permalink to &quot;Step 1: Understand the Radicals&quot;">​</a></h3><p>Tiger Origin is based on 20 core radicals distributed across keyboard keys:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Q W E R T Y U I O P</span></span>
<span class="line"><span> A S D F G H J K L</span></span>
<span class="line"><span>  Z X C V B N M</span></span></code></pre></div><p>Each key corresponds to 1-2 radicals, and radicals with similar shapes are arranged on nearby keys.</p><h3 id="step-2-learn-the-encoding" tabindex="-1">Step 2: Learn the Encoding <a class="header-anchor" href="#step-2-learn-the-encoding" aria-label="Permalink to &quot;Step 2: Learn the Encoding&quot;">​</a></h3><p>Tiger Origin&#39;s encoding rules:</p><ul><li><strong>One-Code Characters</strong>: Common characters with one-key input (e.g., 我, 人, 的)</li><li><strong>Two-Code Characters</strong>: Most common characters with two-key input</li><li><strong>Three-Code Characters</strong>: Most characters with three-key input</li><li><strong>Four-Code Characters</strong>: Complex characters with four-key input</li></ul><h3 id="step-3-start-practicing" tabindex="-1">Step 3: Start Practicing <a class="header-anchor" href="#step-3-start-practicing" aria-label="Permalink to &quot;Step 3: Start Practicing&quot;">​</a></h3><p><a href="/en/practice/top500">Start Common Radicals Practice →</a></p><h2 id="📖-learning-suggestions" tabindex="-1">📖 Learning Suggestions <a class="header-anchor" href="#📖-learning-suggestions" aria-label="Permalink to &quot;📖 Learning Suggestions&quot;">​</a></h2><h3 id="beginner-path" tabindex="-1">Beginner Path <a class="header-anchor" href="#beginner-path" aria-label="Permalink to &quot;Beginner Path&quot;">​</a></h3><ol><li><strong>Day 1</strong>: Complete sequential practice to familiarize with all radicals (about 30-60 minutes)</li><li><strong>Day 2-3</strong>: Random practice to reinforce memory (20-30 minutes daily)</li><li><strong>Week 1-2</strong>: Common radicals special practice</li><li><strong>Ongoing</strong>: Use in daily life to form muscle memory</li></ol><h3 id="learning-tips" tabindex="-1">Learning Tips <a class="header-anchor" href="#learning-tips" aria-label="Permalink to &quot;Learning Tips&quot;">​</a></h3><ul><li><strong>Understanding Memory</strong>: Understand the relationship between radicals and Chinese characters, don&#39;t memorize mechanically</li><li><strong>Multiple Repetitions</strong>: Short and frequent sessions are more effective than long single sessions</li><li><strong>Practical Application</strong>: Use in real scenarios as soon as possible</li><li><strong>Error Review</strong>: Focus on practicing incorrect radicals</li></ul><h3 id="time-schedule" tabindex="-1">Time Schedule <a class="header-anchor" href="#time-schedule" aria-label="Permalink to &quot;Time Schedule&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Stage</th><th>Time</th><th>Goal</th></tr></thead><tbody><tr><td>Beginner</td><td>1-3 days</td><td>Master 20 radicals</td></tr><tr><td>Practice</td><td>1-2 weeks</td><td>Accuracy reaches 80%</td></tr><tr><td>Advanced</td><td>Ongoing</td><td>Speed reaches 60 WPM</td></tr></tbody></table><h2 id="🎓-practice-modes" tabindex="-1">🎓 Practice Modes <a class="header-anchor" href="#🎓-practice-modes" aria-label="Permalink to &quot;🎓 Practice Modes&quot;">​</a></h2><p>We provide multiple practice modes to help you learn progressively:</p><table tabindex="0"><thead><tr><th>Practice Mode</th><th>Description</th><th>Recommended Stage</th></tr></thead><tbody><tr><td><a href="/en/practice/top500">Common Radicals</a></td><td>Special practice for high-frequency radicals</td><td>Beginner ✅</td></tr><tr><td><a href="/en/practice/modern">Sequential Practice</a></td><td>Learn all radicals in order</td><td>Practice ✅</td></tr><tr><td><a href="/en/practice/random">Random Practice</a></td><td>Random radical tests</td><td>Advanced ✅</td></tr><tr><td><a href="/en/practice/error">Error Book</a></td><td>Practice incorrect radicals</td><td>Ongoing ✅</td></tr></tbody></table><h2 id="❓-faq" tabindex="-1">❓ FAQ <a class="header-anchor" href="#❓-faq" aria-label="Permalink to &quot;❓ FAQ&quot;">​</a></h2><h3 id="q-how-long-does-it-take-to-learn" tabindex="-1">Q: How long does it take to learn? <a class="header-anchor" href="#q-how-long-does-it-take-to-learn" aria-label="Permalink to &quot;Q: How long does it take to learn?&quot;">​</a></h3><p><strong>A</strong>: Generally, you can master 20 radicals in 30 minutes and become proficient within 1-2 weeks.</p><h3 id="q-what-are-the-advantages-compared-to-wubi" tabindex="-1">Q: What are the advantages compared to Wubi? <a class="header-anchor" href="#q-what-are-the-advantages-compared-to-wubi" aria-label="Permalink to &quot;Q: What are the advantages compared to Wubi?&quot;">​</a></h3><p><strong>A</strong>: Fewer radicals (20 vs 130+), gentler learning curve, faster to get started.</p><h3 id="q-what-typing-speed-can-be-achieved" tabindex="-1">Q: What typing speed can be achieved? <a class="header-anchor" href="#q-what-typing-speed-can-be-achieved" aria-label="Permalink to &quot;Q: What typing speed can be achieved?&quot;">​</a></h3><p><strong>A</strong>: After 1-2 weeks of practice, most users can reach 60+ WPM.</p><h3 id="q-is-it-suitable-for-absolute-beginners" tabindex="-1">Q: Is it suitable for absolute beginners? <a class="header-anchor" href="#q-is-it-suitable-for-absolute-beginners" aria-label="Permalink to &quot;Q: Is it suitable for absolute beginners?&quot;">​</a></h3><p><strong>A</strong>: Very suitable! Tiger Origin is designed to lower the learning barrier, beginners can quickly get started.</p><h2 id="🔧-download-install" tabindex="-1">🔧 Download &amp; Install <a class="header-anchor" href="#🔧-download-install" aria-label="Permalink to &quot;🔧 Download &amp; Install&quot;">​</a></h2><p><a href="http://ziyuan.ysepan.com/" target="_blank" rel="noreferrer">Tiger Origin Download</a></p><p>Supports Windows and Android platforms.</p><h2 id="🤝-community-support" tabindex="-1">🤝 Community Support <a class="header-anchor" href="#🤝-community-support" aria-label="Permalink to &quot;🤝 Community Support&quot;">​</a></h2><ul><li><strong>QQ Group</strong>: Click the QQ icon in the top right corner to join</li><li><strong>Official Website</strong>: <a href="http://ziyuan.ysepan.com/" target="_blank" rel="noreferrer">Tiger Origin Resources</a></li></ul><h2 id="💡-get-started-now" tabindex="-1">💡 Get Started Now <a class="header-anchor" href="#💡-get-started-now" aria-label="Permalink to &quot;💡 Get Started Now&quot;">​</a></h2><p>Ready to start learning?</p><p><a href="/en/practice/top500">Start Common Radicals Practice →</a></p><hr><p>Happy learning and may your typing efficiency soar!</p>`,48)]))}const g=a(n,[["render",o]]);export{u as __pageData,g as default};
